import{_ as l,e as i}from"./app.6e60246e.js";const e={},o=i('<h2 id="\u6982\u8FF0" tabindex="-1"><a class="header-anchor" href="#\u6982\u8FF0" aria-hidden="true">#</a> \u6982\u8FF0</h2><ul><li>\u4E00\u79CD\u865A\u8BCD\uFF1B</li><li>\u8FDE\u63A5\u8BCD\u4E0E\u8BCD\uFF0C\u77ED\u8BED\u4E0E\u77ED\u8BED\uFF0C\u53E5\u5B50\u4E0E\u53E5\u5B50\uFF1B\u8D77\u5230\u91CD\u8981\u7684\u8854\u63A5\u4F5C\u7528\uFF1B</li></ul><h2 id="\u53E5\u5B50\u4E0E\u53E5\u5B50\u7684\u8FDE\u63A5" tabindex="-1"><a class="header-anchor" href="#\u53E5\u5B50\u4E0E\u53E5\u5B50\u7684\u8FDE\u63A5" aria-hidden="true">#</a> \u53E5\u5B50\u4E0E\u53E5\u5B50\u7684\u8FDE\u63A5</h2><ul><li><p>\u53E5\u5185\u8BED\u6CD5\uFF1A\u4E00\u4E2A\u53E5\u5B50\u4E2D\u7684\u8BED\u6CD5\u89C4\u5219\uFF1B</p></li><li><p>\u591A\u53E5\u8BED\u6CD5\uFF1A\u591A\u4E2A\u53E5\u5B50\u8FDE\u63A5\u7684\u8BED\u6CD5\u89C4\u5219\uFF1B</p></li><li><p>\u4E09\u79CD\u8FDE\u63A5\u65B9\u5F0F: <code>\u7528\u4EC0\u4E48\u8FDE\u63A5\u53E5\u5B50</code></p><ul><li><p>\u7279\u6B8A\u7B26\u53F7\u8FDE\u63A5</p><ol><li>\u5192\u53F7\uFF1A\u901A\u5E38\u7528\u6765\u8FDE\u63A5\u8865\u5145\u8BF4\u660E\u4FE1\u606F\uFF1B</li><li>\u5206\u53F7\uFF1A\u4E0D\u8981\u5F3A\u8C03\u903B\u8F91\u5173\u7CFB\u7684\u65F6\u5019\uFF0C\u53EF\u4EE5\u76F4\u63A5\u8FDE\u63A5\u4E24\u4E2A\u53E5\u5B50\uFF1B</li><li>\u7834\u6298\u53F7\uFF1A \u8865\u5145\u8BF4\u660E\u4FE1\u606F\u7684\uFF0C\u975E\u6B63\u5F0F\u7684\u8FDE\u63A5\u53E5\u5B50\u7684\u65B9\u5F0F\uFF0C\uFF08\u907F\u514D\u4F7F\u7528\uFF1B</li></ol></li><li><p>\u5E76\u5217\u8FDE\u8BCD\u8FDE\u63A5</p><ol><li>\u8FDE\u63A5\u4E24\u4E2A <code>\u5730\u4F4D\u5BF9\u7B49</code> \u7684\u53E5\u5B50\uFF0C\u5728\u8BED\u6CD5\u4E0A\u540C\u6837\u91CD\u8981\uFF1B\u5E76\u5217\u53E5\u5B50\u53EF\u4EE5\u62C6\u5206\u6210\u72EC\u7ACB\u5B58\u5728\u7684\u4E24\u4E2A\u5355\u53E5\uFF1B</li><li>for,and,nor,but,or,yet,so;</li></ol></li><li><p>\u4ECE\u5C5E\u8FDE\u8BCD\u8FDE\u63A5</p><ol><li>\u8FDE\u63A5\u4E24\u4E2A\u5730\u4F4D\u4E0D\u5BF9\u7B49\u7684\u53E5\u5B50\uFF0C\u5728\u8BED\u6CD5\u4E24\u90E8\u5206\u662F\u5206 <code>\u4E3B\u4ECE\u5173\u7CFB</code> \u7684\uFF1B\u5355\u72EC\u7684\u4ECE\u53E5\u4E0D\u80FD\u72EC\u7ACB\u5B58\u5728\uFF1B</li><li>\u6240\u6709\u7684\u4ECE\u53E5\u7684\u8FDE\u8BCD\uFF0C\u90FD\u662F\u4ECE\u5C5E\u8FDE\u8BCD</li><li>\u4ECE\u5C5E\u8FDE\u8BCD\u5217\u8868</li></ol><ul><li>\u540D\u8BCD\u6027\u4ECE\u53E5\u8FDE\u8BCD\uFF1A that, whether, what, how, when</li><li>\u526F\u8BCD\u6027\u4ECE\u53E5\u8FDE\u8BCD\uFF1A before, after, although, because</li><li>\u5F62\u5BB9\u8BCD\u6027\u4ECE\u53E5\u8FDE\u8BCD\uFF1A that, which, who, when, where</li></ul></li></ul></li><li><p>\u4ECE\u53E5\u6982\u8FF0\uFF1A <code>\u7528\u53E5\u5B50\u6765\u505A\u53E5\u5B50\u4E2D\u7684\u67D0\u4E2A\u6210\u5206\uFF1B</code></p><ul><li>\u6210\u4E3A\u4ECE\u53E5\u7684\u65B9\u5F0F\u662F\uFF1A\u5E26\u4E0A\u4ECE\u5C5E\u8FDE\u8BCD\uFF1B \u4EA4\u4EE3\u4E00\u4E2A\u4E8B\u7269 <code>\u540D\u8BCD\u6027</code> /\u63CF\u8FF0\u4E00\u4E2A\u4E1C\u897F <code>\u5B9A\u8BED</code> /\u4EA4\u4EE3\u4E00\u4E2A\u80CC\u666F <code>\u72B6\u8BED</code> \uFF1B</li></ul></li><li><p>\u53E5\u4E0E\u53E5\u7684\u5173\u7CFB</p><ol><li>\u53EA\u6709\u4E00\u5957\u4E3B\u8C13\u7ED3\u6784</li></ol><ul><li>\u7B80\u5355\u53E5</li></ul><ol start="2"><li>\u6709\u4E24\u5957\u53CA\u5176\u4EE5\u4E0A\u4E3B\u8C13\u7ED3\u6784</li></ol><ul><li>\u5E76\u5217\u53E5</li><li>\u4E3B\u4ECE\u53E5</li></ul><ol start="3"><li>\u590D\u5408\u53E5 <code>\u5E76\u5217\u53E5\u548C\u4E3B\u4ECE\u53E5\u7684\u7EDF\u79F0</code> \uFF0C\u590D\u6742\u53E5 <code>\u540C\u65F6\u5305\u542B\u5E76\u5217\u53E5\u548C\u4E3B\u4ECE\u53E5</code> \uFF1B</li></ol></li></ul><h2 id="\u4E09\u79CD\u53E5\u95F4\u8FDE\u63A5\u8BCD" tabindex="-1"><a class="header-anchor" href="#\u4E09\u79CD\u53E5\u95F4\u8FDE\u63A5\u8BCD" aria-hidden="true">#</a> \u4E09\u79CD\u53E5\u95F4\u8FDE\u63A5\u8BCD</h2><ul><li>\u7EAF\u6B63\u8FDE\u8BCD\uFF0C\u6709\u5B9E\u610F\u4E49\uFF1B</li><li>\u6709\u5B9E\u610F\u4E49\uFF0C\u672C\u8EAB\u4E0D\u662F\u8FDE\u8BCD\uFF0C\u4E3B\u8981\u662F\u7279\u6B8A\u7591\u95EE\u53E5\uFF1B</li><li>\u65E0\u5B9E\u610F\u4E49\uFF0C\u88AB\u501F\u7528\u800C\u6765\uFF0C\u8FDE\u63A5\u4E24\u4E2A\u5B8C\u6574\u53E5\u5B50\uFF1B</li><li>\u8FDE\u63A5 <code>\u540D\u8BCD\u6027\u4ECE\u53E5</code> \u7684\u8BCD\u53EB\uFF1A <code>\u8FDE\u63A5\u8BCD/\u5F15\u5BFC\u8BCD</code> \uFF1B</li><li>\u8FDE\u63A5 <code>\u5B9A\u8BED\u4ECE\u53E5</code> \u7684\u8BCD\u53EB\uFF1A <code>\u5173\u7CFB\u8BCD</code> \uFF1B</li><li>\u8FDE\u63A5 <code>\u72B6\u8BED\u4ECE\u53E5</code> \u7684\u8BCD\u53EB\uFF1A <code>\u4ECE\u5C5E\u8FDE\u8BCD </code> \uFF1B</li><li>\u4EE3\u8BCD\u8FDE\u8BCD\u5F15\u5BFC <code>\u7F3A\u7701\u7684\u4E3B\u8C13\u5BBE</code> \u53E5\u5B50\uFF0C\u526F\u8BCD\u8FDE\u8BCD\u8FDE\u63A5 <code>\u5B8C\u6574\u4E3B\u8C13\u5BBE</code> \u53E5\u5B50</li></ul><h2 id="\u7279\u6B8A\u7591\u95EE\u8BCD\u4F5C\u8FDE\u8BCD" tabindex="-1"><a class="header-anchor" href="#\u7279\u6B8A\u7591\u95EE\u8BCD\u4F5C\u8FDE\u8BCD" aria-hidden="true">#</a> \u7279\u6B8A\u7591\u95EE\u8BCD\u4F5C\u8FDE\u8BCD</h2><ul><li><p>\u7C7B\u578B</p><ul><li>where</li><li>what</li><li>when</li><li>which</li><li>who</li><li>whom (\u5BBE\u683C)</li><li>whose ()</li><li>why (\u95EE\u539F\u56E0)</li><li>how (\u95EE\u7A0B\u5EA6)</li></ul></li><li><p>\u7279\u6B8A\u7591\u95EE\u53E5\u63A5\u540D\u6B21\u6027\u4ECE\u53E5 <code>(\u6240\u6709\u7684\u7279\u6B8A\u7591\u95EE\u8BCD\u90FD\u53EF\u4EE5\u5F15\u5BFC\u540D\u8BCD\u6027\u4ECE\u53E5)</code></p><ul><li>\u7279\u6B8A\u7591\u95EE\u53E5\u505A\u540D\u8BCD\u6027\u6210\u5206\uFF0C\u7279\u6B8A\u7591\u95EE\u8BCD\u662F\u5176\u6700\u539F\u59CB\u7684\u542B\u4E49\uFF08\u8868\u7591\u95EE</li><li>\u6574\u4E2A\u4ECE\u53E5\u4F5C <code>\u540D\u8BCD\u6027</code> \u6210\u5206\uFF1B <code>\u4E3B\uFF0C\u8868\uFF0C\u5BBE\uFF0C\u540C\u4F4D\uFF1A \u8868\u793A\uFF1A\u4EC0\u4E48\u7684\u610F\u601D\uFF1B \u4F8B\u5982\uFF1A \u4EC0\u4E48\u65F6\u5019\uFF0C\u4EC0\u4E48\u5730\u65B9\uFF0C\u4EC0\u4E48\u539F\u56E0\uFF0C\u4EC0\u4E48\u65B9\u5F0F</code></li></ul></li><li><p>\u7279\u6B8A\u7591\u95EE\u53E5\u63A5\u72B6\u8BED\u4ECE\u53E5\uFF08\u4E3B\u8981\u662F <code>\u4EA4\u4EE3\u4E3B\u53E5\u8C13\u8BED\u52A8\u8BCD\u53D1\u751F\u7684\u65F6\u95F4\uFF0C\u5730\u70B9</code> \uFF1B\u5176\u4ED6\u8BCD\u4E0D\u9002\u5408\u4EA4\u4EE3\u2018\u8F85\u52A9\u6027\u2019\u526F\u8BCD\u6027\u7684\u72B6\u8BED\u4FE1\u606F <code>\u8FD9\u91CC\u53EA\u6709\u4E24\u4E2Awhen,where\u80FD\u5F15\u5BFC\u72B6\u8BED\u4ECE\u53E5</code></p><ul><li>when \uFF08\u5728/\u5F53... \u65F6\u5019\uFF1A \u65F6\u95F4\u72B6\u8BED\u4ECE\u53E5</li><li>where \uFF08\u5728... \u5730\u65B9\uFF1A\u5730\u70B9\u72B6\u8BED\u4ECE\u53E5</li><li><code>\u72B6\u8BED\u4E2D\u7684\u8FDE\u8BCD\u4E00\u822C\u90FD\u4E0D\u505A\u4EFB\u4F55\u6210\u5206\uFF0C\u8D77\u8FDE\u63A5\u4F5C\u7528\uFF0C\u6574\u4E2A\u4ECE\u53E5\u5728\u4EA4\u4EE3\u4E3B\u53E5\u8C13\u8BED\u52A8\u8BCD\u53D1\u751F\u7684\u5730\u70B9\u6216\u8005\u65F6\u95F4\uFF0C\u53E5\u5B50\u91CD\u70B9\u5728\u8C13\u8BED\u52A8\u8BCD</code></li></ul></li><li><p>\u7279\u6B8A\u7591\u95EE\u8BCD\u94FE\u63A5\u5B9A\u8BED\u4ECE\u53E5</p><ul><li>which, who/whom\uFF1A\u53EF\u4EE5\u8FDE\u63A5 <code>\u540E\u884C\u8BCD\u662F\u540D\u8BCD</code> \u7684\u5B9A\u8BED\u4ECE\u53E5\uFF0Cwhich\u4EE3\u66FF\u7269\uFF0Cwho/whom\u4EE3\u66FF\u4EBA\uFF0C\u6B64\u65F6\u7279\u6B8A\u7591\u95EE\u8BCD\u5B8C\u5168\u5931\u53BB\u542B\u4E49\uFF1B</li><li>when, where, why: \u53EF\u4EE5\u8FDE\u63A5 <code>\u540E\u884C\u8BCD\u662F\u72B6\u8BED</code> \u7684\u5B9A\u8BED\u4ECE\u53E5\uFF0C\u6B64\u65F6\u7279\u6B8A\u7591\u95EE\u8BCD\u5B8C\u5168\u5931\u53BB\u542B\u4E49, <code>\u65F6\u95F4\uFF0C\u5730\u70B9\uFF0C\u539F\u56E0\u72B6\u8BED</code> \uFF1B</li><li>\u6574\u4E2A\u4ECE\u53E5 <code>\u4FEE\u9970</code> \u4E3B\u53E5\u4E2D\u7684\u540D\u8BCD\uFF0C\u53E5\u5B50\u91CD\u70B9\u5728 <code>\u88AB\u4FEE\u9970\u7684\u540D\u8BCD</code> \uFF1B</li></ul></li></ul><h2 id="\u8FDE\u63A5\u526F\u8BCD" tabindex="-1"><a class="header-anchor" href="#\u8FDE\u63A5\u526F\u8BCD" aria-hidden="true">#</a> \u8FDE\u63A5\u526F\u8BCD</h2><ul><li><p>\u8868\u8FBE\u67D0\u79CD\u903B\u8F91\u6216\u65F6\u95F4\u5173\u7CFB\uFF0C\u4F7F\u5F97\u4E0A\u4E0B\u6587\u5728\u8BED\u610F\u65B9\u9762\u8FDE\u63A5\u5F97\u66F4\u987A\u7545\uFF1B</p><ul><li>however</li><li>therefore</li><li>hence</li><li>accordingly</li><li>meanwhile</li><li>furthermore</li><li>besides</li><li>then</li></ul></li><li><p>\u8FDE\u63A5\u526F\u8BCD\u4E0E\u8FDE\u8BCD\u7684\u533A\u522B</p><ul><li>however\u548Cbut, \u8FDE\u8BCD\u4E3B\u8981\u7684\u662F <code>\u8BED\u6CD5\u529F\u80FD</code> \u7684\u8FDE\u63A5\uFF0C\u8FDE\u63A5\u53E5\u5B50\uFF0C\u5176\u6B21\u662F\u8FDE\u63A5\u903B\u8F91\uFF1B</li><li>\u8FDE\u63A5\u526F\u8BCD\u4E3B\u8981\u662F <code>\u8FDE\u63A5\u903B\u8F91</code> \uFF0C\u6CA1\u6709\u8BED\u6CD5\u529F\u80FD\uFF1B</li></ul></li><li><p>\u8FDE\u63A5\u526F\u8BCD\u7684\u4F7F\u7528\uFF1A</p></li></ul><h2 id="\u603B\u7ED3" tabindex="-1"><a class="header-anchor" href="#\u603B\u7ED3" aria-hidden="true">#</a> \u603B\u7ED3</h2><ul><li>\u82F1\u8BED\u7684\u8FDE\u8BCD\u627F\u62C5\u91CD\u8981\u7684\u8BED\u6CD5\u529F\u80FD\uFF0C\u662F\u8FDE\u63A5\u53E5\u5B50\u7684\u91CD\u8981\u65B9\u5F0F\uFF1B</li><li>\u82F1\u8BED\u6CE8\u91CD\u663E\u6027\u8FDE\u63A5\uFF0C\u53E5\u5B50\u7684\u8FDE\u63A5\u5904\u9700\u8981\u5F88\u660E\u663E\uFF1B</li><li>\u8FDE\u8BCD\u548C\u8FDE\u63A5\u526F\u8BCD\u5728\u8BED\u6CD5\u5C42\u9762\u6709\u672C\u8D28\u4E0A\u7684\u533A\u522B\uFF1B</li><li><code>\u4E3B\u53E5</code> \u5C45\u4E3B\u5BFC\u5730\u4F4D\uFF1B <code>\u4E24\u4E2A\u53E5\u5B50</code> \u53EA\u80FD\u7531 <code>\u4E00\u79CD\u8FDE\u63A5\u65B9\u5F0F</code> \uFF1B</li></ul><h2 id="\u4ECE\u5C5E\u8FDE\u8BCD" tabindex="-1"><a class="header-anchor" href="#\u4ECE\u5C5E\u8FDE\u8BCD" aria-hidden="true">#</a> \u4ECE\u5C5E\u8FDE\u8BCD</h2><ul><li>now that : \u65E2\u7136</li></ul><p>\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014\u2014</p><ol><li>\u57FA\u672C\u8FDE\u8BCD: \u5E76\u5217\u8FDE\u8BCD\uFF0C\u5BF9\u7B49\u53E5\u5B50\uFF0C\u5355\u8BCD\uFF0C\u77ED\u8BED</li></ol><p>and</p><p>or</p><p>but</p><ol start="2"><li>\u57FA\u672C\u8FDE\u8BCD\u884D\u751F\u7684\u5176\u4ED6\u8FDE\u8BCD</li></ol><p>and: both...and</p><p>or: either...or... neighter...or...</p><p>but\uFF1A not...but... not only...but also...</p><ul><li>\u4EE5\u4E0A\u9664\u4E86both...and... \u8C13\u8BED\u52A8\u8BCD\u5FC5\u987B\u7528\u590D\u6570\u4E4B\u5916\uFF0C\u5176\u4ED6\u90FD\u91C7\u7528\u5C31\u8FD1\u539F\u5219\u3002</li><li>not only\u7684\u53E5\u5B50\u8981\u91C7\u7528\u5012\u88C5\u7ED3\u6784\u3002</li><li>not only... but also \u4E2D\u7684also\u53EF\u4EE5\u7701\u7565\uFF0C\u82E5\u4E0D\u7701\u7565\uFF0C\u8FDE\u63A5\u5355\u8BCD\u6216\u77ED\u8BEDbut also\u4E0D\u80FD\u5206\u5F00\uFF0C\u8FDE\u63A5\u53E5\u5B50\u8981\u5206\u5F00\u3002</li></ul><ol start="3"><li>as well as \u548Crather than\u505A\u5E76\u5217\u8FDE\u8BCD\uFF0C\u8FDE\u63A5\u5BF9\u7B49\u5355\u8BCD\uFF0C\u77ED\u8BED\u548C\u53E5\u5B50</li></ol><ul><li>\u8FDE\u63A5\u4E3B\u8BED\u65F6\uFF0C\u52A8\u8BCD\u8981\u59CB\u7EC8\u968F\u7B2C\u4E00\u4E2A\u4E3B\u8BED\u505A\u53D8\u5316</li></ul><ol start="4"><li>\u526F\u8BCD\u8FDE\u63A5</li></ol><p>because\uFF0Cif\u5F15\u5BFC\u7684\u4ECE\u53E5\u5145\u5F53\u72B6\u8BED\uFF0C\u7C7B\u4F3C\u526F\u8BCD\u529F\u80FD\u3002</p><p>because, though, if, unless, as soon as, once</p><ul><li>\u526F\u8BCD\u8FDE\u8BCD\u51A0\u4E0E\u4EFB\u4F55\u4E00\u4E2A\u4ECE\u53E5\u524D\uFF0C\u8BE5\u4ECE\u53E5\u5C31\u662F\u72B6\u8BED\u4ECE\u53E5\uFF0C\u6574\u4E2A\u72B6\u8BED\u4ECE\u53E5\u89C6\u4E3A\u526F\u8BCD\u3002 \u7528\u6765\u4FEE\u9970\u4E3B\u53E5\uFF0C\u4E0D\u80FD\u5355\u72EC\u5B58\u5728\u3002</li><li>\u526F\u8BCD\u8FDE\u8BCD\u53EA\u80FD\u8FDE\u63A5\u4ECE\u53E5\u3002</li><li>\u72B6\u8BED\u4ECE\u53E5\u7684\u4F4D\u7F6E\uFF0C\u526F\u8BCD\u8FDE\u8BCD\u5F15\u5BFC\u7684\u4ECE\u53E5\u3002\u7F6E\u4E8E\u4E3B\u53E5\u4E4B\u524D\uFF0C\u901A\u5E38\u52A0\u9017\u53F7\uFF1B\u7F6E\u4E8E\u4E3B\u53E5\u4E4B\u540E\uFF0C\u901A\u5E38\u4E0D\u52A0\u9017\u53F7\u3002</li></ul><p>when, if, once(\u4E00\u65E6), as soon as(\u4E00\u65E6)\uFF0Cunless\uFF0C\u5F15\u5BFC\u7684\u4ECE\u53E5\uFF0C\u8868\u793A\u4EE5\u4E00\u79CD\u6761\u4EF6\u65F6\uFF0C\u5F62\u6210\u6761\u4EF6\u72B6\u8BED\u4ECE\u53E5\u3002</p><ol start="5"><li>\u8FDE\u63A5\u6027\u526F\u8BCD</li></ol><p>\u6B64\u7C7B\u526F\u8BCD\u6709\u526F\u8BCD\u610F\u5473\uFF0C\u4F46\u4E0D\u80FD\u505A\u4E3A\u8FDE\u8BCD\u6765\u7528\uFF0Chowever, nevertheless, therefore, thus, moreover\u7B49\uFF0C \u6B64\u7C7B\u526F\u8BCD\u4F7F\u7528\u65F6\uFF0C\u8981\u548C\u4E3B\u53E5\u9694\u5F00\u3002</p>',33);function d(h,c){return o}var r=l(e,[["render",d],["__file","\u8FDE\u8BCD.html.vue"]]);export{r as default};
